/**
 * 文件快照系统 - 类型定义
 * 
 * 对标Rust版本：
 * backend/vcoder/crates/core/src/service/snapshot/types.rs
 */

/**
 * 文件快照
 */
export interface FileSnapshot {
  /** 快照ID */
  snapshotId: string;
  /** 文件路径（相对或绝对） */
  filePath: string;
  /** 内容哈希（用于去重） */
  contentHash: string;
  /** 文件内容（可能被压缩） */
  content: Buffer;
  /** 是否压缩 */
  compressed: boolean;
  /** 时间戳 */
  timestamp: number;
  /** 元数据 */
  metadata: FileMetadata;
}

/**
 * 文件元数据
 */
export interface FileMetadata {
  /** 文件大小（字节） */
  size: number;
  /** 最后修改时间 */
  mtime: number;
  /** 文件权限（Unix） */
  mode?: number;
  /** 文件编码 */
  encoding: string;
}

/**
 * 操作类型
 */
export enum OperationType {
  /** 创建新文件 */
  Create = 'create',
  /** 修改现有文件 */
  Modify = 'modify',
  /** 删除文件 */
  Delete = 'delete',
  /** 重命名文件 */
  Rename = 'rename',
}

/**
 * 文件操作记录
 */
export interface FileOperation {
  /** 操作ID */
  operationId: string;
  /** 会话ID */
  sessionId: string;
  /** Turn索引 */
  turnIndex: number;
  /** 操作序号（同一turn内的顺序） */
  seqInTurn: number;
  /** 操作类型 */
  operationType: OperationType;
  /** 工具名称 */
  toolName: string;
  /** 文件路径 */
  filePath: string;
  /** 操作前快照ID */
  beforeSnapshotId?: string;
  /** 操作后快照ID */
  afterSnapshotId?: string;
  /** 时间戳 */
  timestamp: number;
  /** 额外信息 */
  metadata?: Record<string, unknown>;
}

/**
 * Session快照信息
 */
export interface SessionSnapshotInfo {
  sessionId: string;
  /** 受影响的文件列表 */
  affectedFiles: string[];
  /** 操作总数 */
  operationCount: number;
  /** 创建时间 */
  createdAt: number;
  /** 最后更新时间 */
  updatedAt: number;
}

/**
 * Turn快照信息
 */
export interface TurnSnapshotInfo {
  sessionId: string;
  turnIndex: number;
  /** 该turn修改的文件 */
  modifiedFiles: string[];
  /** 操作数量 */
  operationCount: number;
  /** 时间戳 */
  timestamp: number;
}

/**
 * 快照统计信息
 */
export interface SnapshotStats {
  /** 总快照数 */
  totalSnapshots: number;
  /** 总操作数 */
  totalOperations: number;
  /** 总存储大小（字节） */
  totalStorageBytes: number;
  /** 活跃session数 */
  activeSessions: number;
  /** 最老快照时间 */
  oldestSnapshotTime?: number;
  /** 最新快照时间 */
  newestSnapshotTime?: number;
}

/**
 * 回滚结果
 */
export interface RollbackResult {
  /** 成功回滚的文件列表 */
  restoredFiles: string[];
  /** 失败的操作 */
  failedOperations: Array<{
    operationId: string;
    filePath: string;
    error: string;
  }>;
  /** 总共处理的操作数 */
  totalOperations: number;
  /** 成功操作数 */
  successCount: number;
  /** 失败操作数 */
  failureCount: number;
}

/**
 * 文件变更历史条目
 */
export interface FileChangeEntry {
  /** 操作ID */
  operationId: string;
  /** Session ID */
  sessionId: string;
  /** Turn索引 */
  turnIndex: number;
  /** 操作类型 */
  operationType: OperationType;
  /** 工具名称 */
  toolName: string;
  /** 时间戳 */
  timestamp: number;
  /** 快照ID */
  snapshotId?: string;
}
